// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract Proposal {
    uint256 public yesVotes;
    uint256 public noVotes;
    mapping(address => bool) public hasVoted;

    error AlreadyVoted();

    function vote(bool support) external {
        if ([[SLOT voted_check]]) revert AlreadyVoted();
        [[SLOT mark_voted]]
        [[SLOT tally_branch]]
    }

    function winning() external view returns (bool) {
        return [[SLOT winning_check]];
    }
}
